async function main() {
  console.log(`\n=== SAVING ${PRODUCTS.length} OPEN FARM PRODUCTS ===\n`);

  let ok = 0, fail = 0;

  for (const p of PRODUCTS) {
    const ingredients = p.ingredients.split(",").map(i => i.trim()).filter(i => i.length > 0);
    const saved = await dbSave(p.name, p.brand, ingredients, p.ingredients, "brand", "https://openfarmpet.com");
    const status = saved ? "✓" : "✗";
    console.log(`${status} [${String(ingredients.length).padStart(2)}] ${p.name.substring(0, 65)}`);
    if (saved) ok++; else fail++;
  }

  console.log(`\n=== DONE: ${ok} saved, ${fail} failed ===`);
}

main().catch(console.error);
